const msg = $input.item.json.message || $input.item.json.edited_message;
if (!msg) return { json: { skip: true, chatId: '', fromId: '', text: '', isRegister: false, phone: '', isVoice: false, voiceFileId: '' } };

// זיהוי הודעה קולית
const isVoice = !!(msg.voice && msg.voice.file_id);
const voiceFileId = isVoice ? msg.voice.file_id : '';

if (!msg.text && !isVoice) {
  return { json: { skip: true, chatId: String(msg.chat?.id||''), fromId: String(msg.from?.id||''), text: '', isRegister: false, phone: '', isVoice: false, voiceFileId: '' } };
}

const text = msg.text ? msg.text.trim() : '';
const fromId = String(msg.from?.id || '');
const chatId = String(msg.chat?.id || '');
const isRegister = text.startsWith('/register');
const phone = isRegister ? text.replace('/register','').replace(/[^0-9]/g,'').trim() : '';
return { json: { text, fromId, chatId, isRegister, phone, isVoice, voiceFileId } };

const months = {1:'ינואר',2:'פברואר',3:'מרץ',4:'אפריל',5:'מאי',6:'יוני',7:'יולי',8:'אוגוסט',9:'ספטמבר',10:'אוקטובר',11:'נובמבר',12:'דצמבר'};
const foundTech = $json.foundTech;
const task = $json.task;
const chatId = $json.chatId;
const managerName = $json.managerName || '';
const startStr = $json.taskDate;
const endStr = (($json.taskDateEnd && $json.taskDateEnd !== 'null') ? $json.taskDateEnd : startStr);
function parse(s){ const p=String(s).split('/'); return new Date(Date.UTC(parseInt(p[2]), parseInt(p[1])-1, parseInt(p[0]))); }
function fmt(dt){ return ('0'+dt.getUTCDate()).slice(-2)+'/'+('0'+(dt.getUTCMonth()+1)).slice(-2)+'/'+dt.getUTCFullYear(); }
function sheet(dt){ return dt.getUTCDate() + ' ' + months[dt.getUTCMonth()+1]; }
let s = parse(startStr); let e = parse(endStr);
if (isNaN(s.getTime())) s = e;
if (isNaN(e.getTime())) e = s;
if (e < s) { const t=s; s=e; e=t; }
const MAX = 62;
const out = [];
let cur = new Date(s.getTime());
let guard = 0;
while (cur <= e && guard < MAX) {
  out.push({ json: { foundTech, task, chatId, managerName, taskDate: fmt(cur), sheetName: sheet(cur), startDate: fmt(s), endDate: fmt(e) } });
  cur = new Date(cur.getTime() + 24*60*60*1000);
  guard++;
}
if (out.length === 0) out.push({ json: { foundTech, task, chatId, managerName, taskDate: startStr, sheetName: sheet(s), startDate: fmt(s), endDate: fmt(e) } });
return out;

const vals = $json.values || [];
const techName = $('Build Sheet Name').item.json.foundTech;
const task = $('Build Sheet Name').item.json.task;
const sheetName = $('Build Sheet Name').item.json.sheetName;
const chatId = $('Build Sheet Name').item.json.chatId;
const taskDate = $('Build Sheet Name').item.json.taskDate;

if (!vals || vals.length === 0) {
  return { json: { findOk: false, errorMsg: 'הלוז ל-' + taskDate + ' לא נמצא', chatId } };
}

// Helper: convert col index (0-based) to sheet letter (A, B, ..., Z, AA, AB...)
function colToLetter(n) {
  let s = '';
  n++;
  while (n > 0) {
    n--;
    s = String.fromCharCode(65 + (n % 26)) + s;
    n = Math.floor(n / 26);
  }
  return s;
}

// 1. Detect task + notes columns from header rows (rows 0 and 1)
let taskColIndices = [];
let notesColIndices = [];
for (let r = 0; r <= Math.min(1, vals.length - 1); r++) {
  const hrow = vals[r] || [];
  for (let c = 2; c < hrow.length; c++) {
    const hval = String(hrow[c]||'').trim();
    if (hval === 'משימה') taskColIndices.push(c);
    if (hval === 'הערות') notesColIndices.push(c);
  }
  if (taskColIndices.length > 0) break;
}
if (taskColIndices.length === 0) taskColIndices = [3, 4, 5, 6];

// 2. Find technician row
const normalize = s => String(s||'').trim();
const techNorm = normalize(techName).toLowerCase();

let rowIdx = -1;
for (let i = 0; i < vals.length; i++) {
  const row = vals[i];
  const cellA = normalize(row[0]).toLowerCase();
  const cellB = normalize(row[1]).toLowerCase();
  const full1 = (cellA + ' ' + cellB).trim();
  const full2 = (cellB + ' ' + cellA).trim();
  if (
    cellA === techNorm || cellB === techNorm ||
    full1 === techNorm || full2 === techNorm ||
    (techNorm.length > 2 && cellA.length > 1 && techNorm.includes(cellA)) ||
    (techNorm.length > 2 && cellB.length > 1 && techNorm.includes(cellB)) ||
    (techNorm.length > 2 && cellA.length > 1 && cellA.includes(techNorm)) ||
    (techNorm.length > 2 && cellB.length > 1 && cellB.includes(techNorm))
  ) {
    rowIdx = i;
    break;
  }
}

if (rowIdx === -1) {
  return { json: { findOk: false, errorMsg: 'לא נמצא טכנאי: ' + techName + ' בלוז ל-' + taskDate, chatId } };
}

const row = vals[rowIdx];

// 3. Try משימה columns first
let colIdx = -1;
for (const ci of taskColIndices) {
  if (!String(row[ci]||'').trim()) { colIdx = ci; break; }
}

// 4. If all משימה full -> try הערות column
if (colIdx === -1) {
  for (const ci of notesColIndices) {
    if (!String(row[ci]||'').trim()) { colIdx = ci; break; }
  }
}

// 5. If הערות also full -> overflow to next empty column past all known columns
if (colIdx === -1) {
  const maxKnownCol = Math.max(
    taskColIndices.length ? Math.max.apply(null, taskColIndices) : 0,
    notesColIndices.length ? Math.max.apply(null, notesColIndices) : 0
  );
  for (let c = maxKnownCol + 1; c < 50; c++) {
    if (!String(row[c]||'').trim()) { colIdx = c; break; }
  }
}

if (colIdx === -1) {
  return { json: { findOk: false, errorMsg: 'אין מקום פנוי ל-' + techName + ' ב-' + taskDate, chatId } };
}

const colLetter = colToLetter(colIdx);
return { json: { findOk: true, foundTech: techName, task, sheetName, chatId, taskDate, cellAddr: colLetter + (rowIdx + 1) } };

const months = {1:'ינואר',2:'פברואר',3:'מרץ',4:'אפריל',5:'מאי',6:'יוני',7:'יולי',8:'אוגוסט',9:'ספטמבר',10:'אוקטובר',11:'נובמבר',12:'דצמבר'};
const foundTech = $json.foundTech;
const taskDate = $json.taskDate;
const queryOk = $json.queryOk;
const chatId = $json.chatId;
const searchKeyword = $json.searchKeyword || null;
const errorMsg = $json.errorMsg || '❓ לא הבנתי';
if (!taskDate) {
  return { json: { foundTech, taskDate: null, sheetName: null, chatId, queryOk: false, searchKeyword, errorMsg } };
}
const dp = taskDate.split('/');
const sheetName = parseInt(dp[0]) + ' ' + months[parseInt(dp[1])];
return { json: { foundTech, taskDate, sheetName, chatId, queryOk, searchKeyword, errorMsg } };

const vals = $json.values || [];
const techName = $('Parse Query').item.json.foundTech;
const taskDate = $('Parse Query').item.json.taskDate;
const chatId = $('Parse Query').item.json.chatId;
const searchKeyword = $('Parse Query').item.json.searchKeyword || null;

// Mode 1: search keyword across all techs
if (!techName && searchKeyword) {
  const matches = [];
  for (let i = 0; i < vals.length; i++) {
    const row = vals[i];
    const cellA = String(row[0]||'').trim();
    const cellB = String(row[1]||'').trim();
    const name = cellB ? cellA + ' ' + cellB : cellA;
    if (!name) continue;
    for (let c = 3; c < 20; c++) {
      const cell = String(row[c]||'').trim();
      if (cell && cell.includes(searchKeyword)) {
        matches.push(name + ': ' + cell);
        break;
      }
    }
  }
  let reply;
  if (matches.length === 0) {
    reply = '❌ לא נמצא איש עם "' + searchKeyword + '" ב-' + taskDate;
  } else {
    reply = '🔍 ' + searchKeyword + ' | ' + taskDate + ':\n' + matches.map((m,i) => (i+1)+'. '+m).join('\n');
  }
  return { json: { reply, chatId } };
}

// Mode 2: specific technician
let rowIdx = -1;
for (let i = 0; i < vals.length; i++) {
  const row = vals[i];
  const cellA = String(row[0]||'').trim();
  const cellB = String(row[1]||'').trim();
  const fullName = cellB ? cellA+' '+cellB : cellA;
  if (cellA===techName||cellB===techName||fullName===techName) { rowIdx=i; break; }
}
if (rowIdx === -1) return { json: { reply: '❌ לא נמצא ' + techName + ' בלוז ל-' + taskDate, chatId } };
const row = vals[rowIdx];
const tasks = [];
for (let c = 3; c < 20; c++) { const cell = row[c] ? String(row[c]).trim() : ''; if (cell) tasks.push(cell); }
let reply;
if (tasks.length === 0) {
  reply = '📋 ' + techName + ' — אין משימות רשומות ב-' + taskDate;
} else {
  reply = '📋 ' + techName + ' | ' + taskDate + ':\n' + tasks.map((t,i) => (i+1)+'. '+t).join('\n');
}
return { json: { reply, chatId } };

let text = $('Extract Message').item.json.text;
try { const _vt = $('Inject Voice Text').first().json.text; if (_vt && _vt.trim()) text = _vt.trim(); } catch(e) {}
const chatId = $('Extract Message').item.json.chatId;
const fmt = d => ('0'+d.getUTCDate()).slice(-2)+'/'+('0'+(d.getUTCMonth()+1)).slice(-2)+'/'+d.getUTCFullYear();
const dayNames = ['ראשון','שני','שלישי','רביעי','חמישי','שישי','שבת'];
const nowIL = new Date(Date.now() + 3*60*60*1000);
const todayDay = dayNames[nowIL.getUTCDay()];
const todayStr = fmt(nowIL);
const tomorrowStr = fmt(new Date(nowIL.getTime() + 24*60*60*1000));
const yesterdayStr = fmt(new Date(nowIL.getTime() - 24*60*60*1000));
const dayAfterStr = fmt(new Date(nowIL.getTime() + 48*60*60*1000));

let ctxBlock = '';
try {
  const sd = $getWorkflowStaticData('global');
  const ctx = sd['ctx_' + chatId];
  if (ctx && ctx.taskDate) {
    const dp = ctx.taskDate.split('/');
    const ctxDate = new Date(Date.UTC(parseInt(dp[2]), parseInt(dp[1])-1, parseInt(dp[0])));
    const ctxDayName = dayNames[ctxDate.getUTCDay()];
    ctxBlock = '

=== CONVERSATION CONTEXT ===
User previously asked about: ' + (ctx.foundTech || 'all techs') + ' on ' + ctx.taskDate + ' (' + ctxDayName + ').
CRITICAL: Relative date expressions in follow-ups are relative to CONTEXT DATE (' + ctx.taskDate + '), NOT today (' + todayStr + ').
Examples: "ויום לפני?" = one day before ' + ctx.taskDate + ', "ובשבוע שלפני?" = 7 days before.
If no tech name in message, reuse foundTech="' + (ctx.foundTech || 'null') + '".
=== END CONTEXT ===';
  }
} catch(e) {}

let clarifyBlock = '';
try {
  const sd2 = $getWorkflowStaticData('global');
  const cl = sd2['clarify_' + chatId];
  if (cl) {
    clarifyBlock = '

=== CLARIFICATION IN PROGRESS ===
The user is answering a clarification for an ADD (schedule task) request. Known so far: foundTech=' + (cl.foundTech || '?') + ', foundDept=' + (cl.foundDept || '?') + ', taskDate=' + (cl.taskDate || '?') + ', task=' + (cl.task || '?') + '.
The new message provides the missing detail(s). MERGE the known fields with the new info and return a COMPLETE add JSON (intent MUST be "add"). Keep known non-null fields unless the user explicitly changes them. For dates use the DATE REFERENCE exactly.
=== END CLARIFICATION ===';
  }
} catch(e) {}

const prompt = 'You are an intent+date parser for a Hebrew employee scheduling bot. Today is ' + todayDay + ' (' + todayStr + ').' + ctxBlock + clarifyBlock + '

Technicians by department:
שירות: אלי, אלירן, יוסי, קנדלקר, משה מרגלית, ערן רוזנברג, טום, עידן כידרא, נתנאל, שאול, טל רוטהולץ
גילוי: יותם, מני, ראובן, איציק יעיש, אושרי, משה מויאל, אבירן, משה צח, הראל, לירון, נדב, שמואל, מנדי, ינון, בר נתן, אריאל
מתזים: נאור, אנטון, יוסף, גמאל, אליאס, אופיר, טים, דודי
משאבות: ולאדיק, אלכס, חמודי, מיכאל, יעקב, ארטור

Return ONLY valid JSON (no markdown):
{"intent":"query or add or daily or unknown","foundTech":"tech name or null","foundDept":"dept or null","taskDate":"DD/MM/YYYY or null","task":"task description or null","searchKeyword":"Hebrew keyword to search ALL techs or null"}

intent rules:
- query: asking about a specific tech schedule
- add: adding a task to a technician schedule. Includes MANY Hebrew phrasings, ALL meaning add-to-schedule: "תפתח קריאת שירות ל...", "תפתח קריאה ל...", "תרשום ל...", "תכניס ל...", "תוסיף ל...", "תשבץ את...", "שים ל...", "צריך לשלוח את... ל...", "תזמן ל...". CRITICAL: the words "קריאת שירות" or "קריאה" in this bot ALWAYS mean a schedule task — treat as add.
- daily: asking for full schedule for a date ("מה הלוז היום?", "תראה לי את הלוז", "מי עובד מחר?") — set taskDate, foundDept optional
- searchKeyword: when asking "who was on vacation/sick" across all techs

DATE REFERENCE (use these EXACT dates, DO NOT recalculate):
- היום / today = ' + todayStr + '
- מחר / tomorrow = ' + tomorrowStr + '
- מחרתיים / day after tomorrow = ' + dayAfterStr + '
- אתמול / yesterday = ' + yesterdayStr + '

Date rules:
- For היום/מחר/מחרתיים/אתמול use the DATE REFERENCE above EXACTLY.
- יום שלישי שעבר=last Tuesday, etc. — compute from today (' + todayStr + ').
- DD.MM or DD/MM without year=2026

Examples:
- "תפתח קריאת שירות למשה מרגלית למחר על תקלה במבנה נריה" → {"intent":"add","foundTech":"משה מרגלית","foundDept":"שירות","taskDate":"' + tomorrowStr + '","task":"תקלה במבנה נריה"}
- "תוסיף לאלי מחר ביקורת שנתית בקיסריה" → {"intent":"add","foundTech":"אלי","foundDept":"שירות","taskDate":"' + tomorrowStr + '","task":"ביקורת שנתית בקיסריה"}
- "מה הלוז של נאור מחר?" → {"intent":"query","foundTech":"נאור","taskDate":"' + tomorrowStr + '"}

Message: ' + text;

return { json: {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 200,
  messages: [{ role: 'user', content: prompt }]
}};

const chatId = $('Extract Message').item.json.chatId;
const managerDept = $('Find Manager').item.json.department;
const managerName = $('Find Manager').item.json.name;

let parsed = null;
try {
  const text = ($json.content && $json.content[0] && $json.content[0].text) ? $json.content[0].text : '';
  const match = text.match(/\{[\s\S]*?\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch(e) {}

const sd = $getWorkflowStaticData('global');
const clarifyKey = 'clarify_' + chatId;
const existingClarify = sd[clarifyKey] || null;

if (!parsed) {
  return { json: { intent: 'unknown', foundTech: null, foundDept: null, taskDate: null, task: null, searchKeyword: null, parseOk: false, queryOk: false, canEdit: false, chatId, managerName, needsClarification: false, errorMsg: existingClarify ? '❓ לא הבנתי את התשובה — נסה שוב' : '❓ לא הבנתי, נסה שוב' } };
}

let intent = parsed.intent || 'unknown';
let foundTech = (parsed.foundTech && parsed.foundTech !== 'null') ? String(parsed.foundTech) : null;
let foundDept = (parsed.foundDept && parsed.foundDept !== 'null') ? String(parsed.foundDept) : null;
let taskDate = (parsed.taskDate && parsed.taskDate !== 'null') ? String(parsed.taskDate) : null;
let task = (parsed.task && parsed.task !== 'null') ? String(parsed.task) : '';
const searchKeyword = (parsed.searchKeyword && parsed.searchKeyword !== 'null') ? String(parsed.searchKeyword) : null;

// Clarification merge: if a clarify is open, treat as add-in-progress and merge known fields
if (existingClarify) {
  intent = 'add';
  foundTech = foundTech || existingClarify.foundTech || null;
  foundDept = foundDept || existingClarify.foundDept || null;
  taskDate = taskDate || existingClarify.taskDate || null;
  task = task || existingClarify.task || '';
}

const canEdit = managerDept === 'all' || managerDept === foundDept;
const parseOk = intent === 'add' && !!foundTech && !!taskDate && !!task;
const queryOk = intent === 'query' && (!!foundTech || (!!searchKeyword && !!taskDate));

let errorMsg = '❓ לא הבנתי — ניתן לשאול על לוז או להוסיף משימה';
let needsClarification = false;

if (intent === 'add' && !parseOk) {
  const prevRounds = existingClarify ? (existingClarify.rounds || 0) : 0;
  const rounds = prevRounds + 1;
  if (rounds > 3) {
    delete sd[clarifyKey];
    errorMsg = 'בוא ננסה מחדש — תאר בהודעה אחת: שם הטכנאי, התאריך, ומה לרשום';
  } else {
    sd[clarifyKey] = { foundTech, foundDept, taskDate, task, rounds };
    needsClarification = true;
    if (!foundTech) errorMsg = 'לאיזה טכנאי לרשום?';
    else if (!taskDate) errorMsg = foundTech ? ('לאיזה תאריך לרשום את המשימה ל' + foundTech + '?') : 'לאיזה תאריך לרשום?';
    else errorMsg = 'מה לרשום (תיאור המשימה)?';
  }
} else if (intent === 'add' && parseOk) {
  delete sd[clarifyKey];
} else if (intent === 'query') {
  if (!foundTech && !searchKeyword) errorMsg = '❓ לא זיהיתי שם טכנאי — ציין שם מהרשימה';
  else if (!taskDate) errorMsg = '❓ לא זיהיתי תאריך — הוסף תאריך כמו "מחר" או "25/06"';
} else if (intent === 'daily') {
  if (!taskDate) errorMsg = '❓ לא זיהיתי תאריך ללוז';
}

return { json: { intent, foundTech, foundDept, taskDate, task, searchKeyword, parseOk, queryOk, canEdit, chatId, managerName, errorMsg, needsClarification } };

const chatId = $('Parse Query').item.json.chatId;
const foundTech = $('Parse Query').item.json.foundTech;
const taskDate = $('Parse Query').item.json.taskDate;
try {
  const sd = $getWorkflowStaticData('global');
  if (chatId && foundTech) sd['ctx_'+chatId] = { foundTech, taskDate };
} catch(e) {}
return $input.item;

const chatId = $('Execute Pending').item.json.chatId;
const foundTech = $('Execute Pending').item.json.foundTech;
const taskDate = $('Execute Pending').item.json.startDate;
try {
  const sd = $getWorkflowStaticData('global');
  if (chatId && foundTech) sd['ctx_'+chatId] = { foundTech, taskDate };
} catch(e) {}
return $input.item;

const months = {1:'ינואר',2:'פברואר',3:'מרץ',4:'אפריל',5:'מאי',6:'יוני',7:'יולי',8:'אוגוסט',9:'ספטמבר',10:'אוקטובר',11:'נובמבר',12:'דצמבר'};
const taskDate = $json.taskDate;
const chatId = $json.chatId;
const foundDept = $json.foundDept || null;
if (!taskDate) {
  return { json: { taskDate: null, sheetName: null, chatId, foundDept, dailyOk: false } };
}
const dp = taskDate.split('/');
const sheetName = parseInt(dp[0]) + ' ' + months[parseInt(dp[1])];
return { json: { taskDate, sheetName, chatId, foundDept, dailyOk: true } };

const vals = $json.values || [];
const taskDate = $('Parse Daily').item.json.taskDate;
const chatId = $('Parse Daily').item.json.chatId;
const nl = String.fromCharCode(10);

if (!vals || vals.length === 0) {
  return { json: { reply: '❌ לא נמצא לוז ל-' + taskDate, chatId } };
}

let taskCols = [];
for (let r = 0; r <= 1; r++) {
  const hr = vals[r] || [];
  for (let c = 2; c < hr.length; c++) {
    if (String(hr[c]||'').trim() === 'משימה') taskCols.push(c);
  }
  if (taskCols.length > 0) break;
}
if (taskCols.length === 0) taskCols = [3,4,5,6];

const lines = [];
for (let i = 2; i < vals.length; i++) {
  const row = vals[i];
  const cellB = String(row[1]||'').trim();
  if (!cellB || cellB.length < 2) continue;
  const tasks = [];
  for (const c of taskCols) {
    const cell = String(row[c]||'').trim();
    if (cell) tasks.push(cell);
  }
  if (tasks.length > 0) {
    lines.push('• ' + cellB + ': ' + tasks.join(' | '));
  }
}

const header = lines.length === 0
  ? '📋 אין משימות רשומות ב-' + taskDate
  : '📋 לוז ' + taskDate + ' (' + lines.length + ' טכנאים):';

const reply = lines.length === 0 ? header : header + nl + lines.join(nl);

return { json: { reply, chatId } };

const chatId = $json.chatId;
if (!chatId) return { json: { ...$json, hasPending: false, pendingAction: null } };
const text = ($json.text || '').trim();
const sd = $getWorkflowStaticData('global');

// Clear clarify on explicit cancel or /register
if (text.startsWith('/register') || text === 'בטל' || text === 'ביטול') {
  delete sd['clarify_' + chatId];
}

const pending = sd['pending_' + chatId];
if (pending) {
  if (text === 'כן' || text === 'yes') {
    return { json: { ...$json, hasPending: true, pendingAction: 'confirm' } };
  } else if (text === 'לא' || text === 'no' || text === 'בטל') {
    delete sd['pending_' + chatId];
    return { json: { ...$json, hasPending: true, pendingAction: 'cancel' } };
  }
  // New command while pending — clear pending and continue normally
  delete sd['pending_' + chatId];
}
return { json: { ...$json, hasPending: false, pendingAction: null } };

const chatId = $json.chatId;
const action = $json.pendingAction;
const sd = $getWorkflowStaticData('global');
const pending = sd['pending_' + chatId];
if (action === 'confirm' && pending) {
  delete sd['pending_' + chatId];
  return { json: {
    action: 'confirm',
    cells: pending.cells || [],
    task: pending.task,
    chatId: pending.chatId,
    foundTech: pending.foundTech,
    startDate: pending.startDate,
    endDate: pending.endDate,
    count: (pending.cells || []).length,
    managerName: pending.managerName || ''
  }};
}
delete sd['pending_' + chatId];
return { json: { action: 'cancel', chatId } };

const items = $input.all();
const sd = $getWorkflowStaticData('global');
let chatId = '', foundTech = '', task = '', startDate = '', endDate = '', managerName = '';
try {
  const b = $('Build Sheet Name').first().json;
  chatId = b.chatId; foundTech = b.foundTech; task = b.task; startDate = b.startDate; endDate = b.endDate; managerName = b.managerName || '';
} catch(e) {}
const cells = [];
for (const it of items) {
  const j = it.json || {};
  if (j.findOk && j.cellAddr && j.sheetName) cells.push({ sheetName: j.sheetName, cellAddr: j.cellAddr, taskDate: j.taskDate });
}
const total = items.length;
const count = cells.length;
const skipped = total - count;
if (count > 0 && chatId) {
  sd['pending_' + chatId] = { foundTech, task, chatId, cells, startDate, endDate, count, managerName };
}
const errorMsg = count > 0 ? '' : 'לא נמצא מקום פנוי או גיליון מתאים בטווח שביקשת';
return { json: { chatId, foundTech, task, startDate, endDate, count, skipped, total, errorMsg } };

const transcript = $('Whisper Transcribe').first().json.text || '';
const base = $('Extract Message').first().json;
return { json: {
  ...base,
  text: transcript.trim(),
  isVoice: false
} };

const ep = $('Execute Pending').first().json;
const cells = ep.cells || [];
const task = ep.task, foundTech = ep.foundTech, chatId = ep.chatId;
if (!cells.length) return [];
return cells.map(c => ({ json: { sheetName: c.sheetName, cellAddr: c.cellAddr, taskDate: c.taskDate, task, foundTech, chatId } }));

const items = $input.all();
let written = 0;
for (const it of items) {
  const j = it.json || {};
  if (j && !j.error) written++;
}
return { json: { written: written || items.length } };
